+
+fn visible_width(s: &str) -> usize {
+    let mut width = 0;
+    let mut in_escape = false;
+
+    for c in s.chars() {
+        if c == '\x1b' {
+            in_escape = true;
+            continue;
+        }
+        if in_escape {
+            if c == 'm' {
+                in_escape = false;
+            }
+            continue;
+        }
+        width += UnicodeWidthChar::width(c).unwrap_or(0);
+    }
+
+    width
+}
+
+fn cut_line(line: &str, start: usize, width: usize) -> String {
+    if width == 0 {
+        return String::new();
+    }
+
+    let end = start.saturating_add(width);
+    let mut result = String::new();
+    let mut in_escape = false;
+    let mut visible = 0;
+
+    for c in line.chars() {
+        if c == '\x1b' {
+            in_escape = true;
+            result.push(c);
+            continue;
+        }
+        if in_escape {
+            result.push(c);
+            if c == 'm' {
+                in_escape = false;
+            }
+            continue;
+        }
+
+        let cw = UnicodeWidthChar::width(c).unwrap_or(0);
+        if visible + cw <= start {
+            visible += cw;
+            continue;
+        }
+        if visible >= end {
+            break;
+        }
+        result.push(c);
+        visible += cw;
+    }
+
+    result
+}
